// Aggregate runs into a 3-line Georgian Telegram message.
// Mirrors scripts.observer.daily_spend_report._format_message().
const rows = $input.first().json || [];
const arr = Array.isArray(rows) ? rows : [];

let llmCalls = 0;
let llmSpend = 0;
const cron = {};
const labels = {
  perception_tick: 'perception',
  weekly_brief_trigger: 'weekly',
  weekly_brief: 'weekly',
  urgent_alert: 'urgent',
  daily_digest: 'digest',
  fire_drill: 'fire-drill',
  budget_lock: 'budget-lock',
  agent_run: 'agent',
  validation_workflow: 'validation',
  daily_spend_report: 'spend-report',
};
for (const r of arr) {
  if (r.kind === 'llm_call') {
    llmCalls += 1;
    llmSpend += parseFloat(r.token_cost || 0);
  } else {
    cron[r.kind] = (cron[r.kind] || 0) + 1;
  }
}
const cap = 1.5;
const pct = (llmSpend / cap) * 100;
const overCap = llmSpend > cap;
const warn = overCap ? '\u26A0\uFE0F ' : '';
const cronParts = Object.keys(cron).sort().map(k => `${cron[k]} ${labels[k] || k}`);
const cronLine = 'Cron: ' + (cronParts.length ? cronParts.join(' \u00B7 ') : '0 runs');
const lines = [
  '\uD83D\uDCCA ALEKSANDRA_BRAIN \u2014 \u10d2\u10e3\u10e8\u10d8\u10dc\u10d3\u10d4\u10da\u10d8 \u10ee\u10d0\u10e0\u10ef\u10d8',
  `${warn}LLM: ${llmCalls} \u10ea\u10d3\u10d0 \u00B7 $${llmSpend.toFixed(4)} (\u10d1\u10d8\u10e3\u10ef\u10d4\u10e2\u10d8 ${pct.toFixed(1)}%)`,
  cronLine,
];
if (overCap) lines.push('\u10db\u10d8\u10d4\u10ea\u10d4\u10e1 \u10d2\u10d0\u10d3\u10d0\u10ee\u10d4\u10d3\u10d5\u10d0');
return [{ json: { text: lines.join('\n'), llmCalls, llmSpend, overCap, summary: { window_hours: 24, llm_calls: llmCalls, llm_spend_usd: llmSpend, cron_runs: cron, budget_cap_usd: cap, pct_of_cap: pct, over_cap: overCap } } }];
